// Filter PRs merged in the last 7 days
const oneWeekAgo = new Date();
oneWeekAgo.setDate(oneWeekAgo.getDate() - 7);

const items = $input.all();
const allPRs = items[0].json;

const recentMerged = allPRs.filter(pr => {
  if (!pr.merged_at) return false;
  const mergedDate = new Date(pr.merged_at);
  return mergedDate >= oneWeekAgo;
});

const summary = {
  total_merged: recentMerged.length,
  total_additions: recentMerged.reduce((sum, pr) => sum + (pr.additions || 0), 0),
  total_deletions: recentMerged.reduce((sum, pr) => sum + (pr.deletions || 0), 0),
  prs: recentMerged.map(pr => ({
    number: pr.number,
    title: pr.title,
    author: pr.user?.login || 'unknown',
    merged_at: pr.merged_at,
    additions: pr.additions || 0,
    deletions: pr.deletions || 0,
    url: pr.html_url,
    labels: (pr.labels || []).map(l => l.name)
  }))
};

return [{ json: summary }];

// Generate markdown summary
const data = $input.first().json;

const date = new Date().toLocaleDateString('en-US', { 
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' 
});

let md = `# Weekly Development Summary\n\n`;
md += `**Generated:** ${date}\n`;
md += `**Total PRs Merged:** ${data.total_merged}\n`;
md += `**Total Lines Changed:** +${data.total_additions} / -${data.total_deletions}\n\n`;

// Group by label
const byLabel = {};
data.prs.forEach(pr => {
  pr.labels.forEach(label => {
    if (!byLabel[label]) byLabel[label] = [];
    byLabel[label].push(pr);
  });
});

Object.entries(byLabel).forEach(([label, prs]) => {
  md += `### ${label}\n`;
  prs.forEach(pr => {
    md += `- [#${pr.number}](${pr.url}) ${pr.title} (@${pr.author})\n`;
  });
  md += `\n`;
});

if (data.prs.length === 0) {
  md += `*No PRs merged this week.*\n`;
}

md += `---\n*Generated by Claude Code n8n workflow*\n`;

return [{ json: { summary: md } }];
